import Collections

extension Solution {
    static let MAX_V: Int = 1000000
    static var is_prime: [Bool]? = nil
    static var spf: [Int]? = nil

    static func solve(nums: [Int64]) -> Int64 {
        if Self.is_prime == nil || Self.spf == nil {
            var is_prime_arr = [Bool](repeating: true, count: Self.MAX_V+1)
            var spf_arr = [Int](repeating: 0, count: Self.MAX_V+1)
            is_prime_arr[0] = false
            is_prime_arr[1] = false
            for i in 0...Self.MAX_V {
                spf_arr[i] = i
            }
            for i in 2...Self.MAX_V {
                if spf_arr[i] == i {
                    var j = i * i
                    if j > Self.MAX_V {
                        continue
                    }
                    while j <= Self.MAX_V {
                        is_prime_arr[j] = false
                        if spf_arr[j] == j {
                            spf_arr[j] = i
                        }
                        j += i
                    }
                }
            }
            Self.is_prime = is_prime_arr
            Self.spf = spf_arr
        }

        let n = nums.count
        if n == 1 {
            return 0
        }
        let numsInt = nums.map { Int($0) }

        var S = Set<Int>()
        for num in numsInt {
            if num >= 2 && num <= Self.MAX_V && Self.is_prime![num] {
                S.insert(num)
            }
        }

        var prime_to_indices: [Int: [Int]] = [:]
        for p in S {
            prime_to_indices[p] = []
        }

        for j in 0..<n {
            let x = numsInt[j]
            if x == 1 {
                continue
            }
            var temp = x
            var distinct_primes = Set<Int>()
            while temp > 1 {
                let p = Self.spf![temp]
                distinct_primes.insert(p)
                while temp % p == 0 {
                    temp /= p
                }
            }
            for p in distinct_primes {
                if S.contains(p) {
                    prime_to_indices[p]!.append(j)
                }
            }
        }

        var dist = Array(repeating: -1, count: n)
        var queue = [Int]()
        var head = 0
        dist[0] = 0
        queue.append(0)
        var used_primes = Set<Int>()

        while head < queue.count {
            let i = queue[head]
            head += 1
            if i == n - 1 {
                return Int64(dist[i])
            }
            for step in [-1, 1] {
                let ni = i + step
                if ni >= 0 && ni < n {
                    if dist[ni] == -1 {
                        dist[ni] = dist[i] + 1
                        queue.append(ni)
                    }
                }
            }
            let p_val = numsInt[i]
            if S.contains(p_val) && !used_primes.contains(p_val) {
                used_primes.insert(p_val)
                for j in prime_to_indices[p_val]! {
                    if j == i {
                        continue
                    }
                    if dist[j] == -1 {
                        dist[j] = dist[i] + 1
                        queue.append(j)
                    }
                }
            }
        }
        return Int64(dist[n - 1])
    }
}
