func solve(nums: [Int64]) -> Int64 {
    let M = 1000000
    var isPrime = [Bool](repeating: true, count: M+1)
    isPrime[0] = false
    isPrime[1] = false
    var i = 2
    while i <= M {
        if isPrime[i] {
            var j = i * i
            while j <= M {
                isPrime[j] = false
                j += i
            }
        }
        i += 1
    }

    let n = nums.count
    var number_to_indices = [Int: [Int]]()
    for idx in 0..<n {
        let num = Int(nums[idx])
        if number_to_indices[num] == nil {
            number_to_indices[num] = []
        }
        number_to_indices[num]?.append(idx)
    }

    var distinct_primes = Set<Int>()
    for num_val in nums {
        let val = Int(num_val)
        if val >= 2 && isPrime[val] {
            distinct_primes.insert(val)
        }
    }

    var prime_to_indices = [Int: [Int]]()
    for p in distinct_primes {
        var list = [Int]()
        var k = p
        while k <= M {
            if let indices = number_to_indices[k] {
                list.append(contentsOf: indices)
            }
            k += p
        }
        prime_to_indices[p] = list
    }

    if n == 1 {
        return 0
    }

    var dist = [Int](repeating: -1, count: n)
    var activated_primes = Set<Int>()
    var queue = [Int]()
    dist[0] = 0
    queue.append(0)

    while !queue.isEmpty {
        let u = queue.removeFirst()
        if u == n - 1 {
            break
        }

        for step in [-1, 1] {
            let v = u + step
            if v >= 0 && v < n && dist[v] == -1 {
                dist[v] = dist[u] + 1
                queue.append(v)
            }
        }

        let num_val = Int(nums[u])
        if num_val >= 2 && num_val <= M && isPrime[num_val] {
            let p = num_val
            if !activated_primes.contains(p) {
                activated_primes.insert(p)
                if let tele_list = prime_to_indices[p] {
                    for j in tele_list {
                        if j == u {
                            continue
                        }
                        if dist[j] == -1 {
                            dist[j] = dist[u] + 1
                            queue.append(j)
                        }
                    }
                }
            }
        }
    }

    return Int64(dist[n - 1])
}
