func solve(nums: Array<Int64>): Int64 {
    let n = nums.size()
    if n == 0 {
        return 0
    }

    const MAX_VAL = 1000000
    var spf = makeArray(MAX_VAL + 1, 0)
    for i from 0 to MAX_VAL {
        spf[i] = i
    }

    for i from 2 to MAX_VAL {
        if i * i > MAX_VAL {
            break
        }
        if spf[i] == i {
            var j = i * i
            while j <= MAX_VAL {
                if spf[j] == j {
                    spf[j] = i
                }
                j += i
            }
        }
    }

    var is_prime = makeArray(MAX_VAL + 1, false)
    is_prime[0] = false
    is_prime[1] = false
    for i from 2 to MAX_VAL {
        is_prime[i] = spf[i] == i
    }

    var prime_to_indices = Map<Int, Array<Int>>()

    for j from 0 to n-1 {
        var num = nums[j]
        if num == 1 {
            continue
        }
        var x = num.toInt()
        var temp = x
        var distinct_primes = Set<Int>()
        while temp > 1 {
            var p = spf[temp]
            distinct_primes.add(p)
            while temp % p == 0 {
                temp = temp / p
            }
        }
        for p in distinct_primes {
            if not prime_to_indices.has(p) {
                prime_to_indices.set(p, Array<Int>())
            }
            var list = prime_to_indices.get(p)
            list.append(j)
            prime_to_indices.set(p, list)
        }
    }

    var dist = makeArray(n, -1)
    var q = Deque<Int>()
    dist[0] = 0
    q.push_back(0)

    var used_primes = Set<Int>()

    while not q.empty() {
        var i = q.pop_front()
        var step = dist[i]

        if i == n - 1 {
            return step.toInt64()
        }

        for move in [i - 1, i + 1] {
            if move >= 0 && move < n && dist[move] == -1 {
                dist[move] = step + 1
                q.push_back(move)
            }
        }

        var current = nums[i].toInt()
        if current >= 2 && current <= MAX_VAL && is_prime[current] {
            if not used_primes.contains(current) {
                used_primes.add(current)
                if prime_to_indices.has(current) {
                    var indices = prime_to_indices.get(current)
                    for j in indices {
                        if j != i && dist[j] == -1 {
                            dist[j] = step + 1
                            q.push_back(j)
                        }
                    }
                }
            }
        }
    }

    return -1
}
